package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;

import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testGetQuoteCharacter_Default() {
        CSVFormat format = CSVFormat.DEFAULT;
        Character quoteChar = format.getQuoteCharacter();
        assertNotNull(quoteChar);
        assertEquals('"', quoteChar.charValue());
    }

    @Test
    void testGetQuoteCharacter_NullQuoteCharacter() {
        CSVFormat format = CSVFormat.DEFAULT.withQuote((Character) null);
        Character quoteChar = format.getQuoteCharacter();
        assertNull(quoteChar);
    }

    @Test
    void testGetQuoteCharacter_CustomQuoteCharacter() {
        CSVFormat format = CSVFormat.DEFAULT.withQuote('\'');
        Character quoteChar = format.getQuoteCharacter();
        assertNotNull(quoteChar);
        assertEquals('\'', quoteChar.charValue());
    }

    @Test
    void testGetQuoteCharacter_UsingPredefinedFormats() {
        // EXCEL uses DEFAULT quote character
        Character excelQuote = CSVFormat.EXCEL.getQuoteCharacter();
        assertNotNull(excelQuote);
        assertEquals('"', excelQuote.charValue());

        // MYSQL has null quote character
        Character mysqlQuote = CSVFormat.MYSQL.getQuoteCharacter();
        assertNull(mysqlQuote);

        // INFORMIX_UNLOAD uses DOUBLE_QUOTE_CHAR
        Character informixQuote = CSVFormat.INFORMIX_UNLOAD.getQuoteCharacter();
        assertNotNull(informixQuote);
        assertEquals('"', informixQuote.charValue());

        // POSTGRESQL_CSV uses DOUBLE_QUOTE_CHAR
        Character pgCsvQuote = CSVFormat.POSTGRESQL_CSV.getQuoteCharacter();
        assertNotNull(pgCsvQuote);
        assertEquals('"', pgCsvQuote.charValue());
    }
}
